body:
### Example code

Verilog file `top.v`:
```verilog
module top (O, clk, wire1, wire0);
  output [5:0] O;
  input clk;
  input wire [2:0] wire0;
  input wire [2:0] wire1;
  wire [2:0] wire2;
  wire [2:0] wire3;
  reg [2:0] reg0 /*verilator public_flat*/ = (2'h0);
  reg [2:0] reg1 /*verilator public_flat*/ = (2'h0);
  reg [2:0] reg2 /*verilator public_flat*/ = (2'h0);
  reg [2:0] reg3 /*verilator public_flat*/ = (2'h0);
  reg [2:0] reg4 /*verilator public_flat*/ = (2'h0);

  always @(posedge clk) begin
    if ((-wire1))
      reg0 <= wire1;
    else
      reg1 = wire0;
  end
  always @(posedge clk) begin
    reg2 <= {reg0};
  end
  assign wire3 = (wire0 == reg0);
  assign wire2 = {reg2, wire3, reg0, reg1};

  always @(posedge clk) begin
    if (wire0[1])
      reg4 <= (~&wire2);
    if ((wire2 * wire2))
      reg3 <= $unsigned(wire2);
    else
      reg3 <= reg4;
  end
  assign O = {reg3, reg4, wire2};
endmodule
```

C++ file `main.cpp`:
```cpp
#include "verilated.h"
#include "Vtop.h"

#include <bitset>
#include <iostream>

//======================

int main(int argc, char** argv, char**) {
    // Setup context, defaults, and parse command line
    Verilated::debug(0);
    const std::unique_ptr<VerilatedContext> contextp{new VerilatedContext};
    contextp->commandArgs(argc, argv);

    // Construct the Verilated model, from Vtop.h generated from Verilating
    const std::unique_ptr<Vtop> topp{new Vtop{contextp.get()}};

    // Simulate
    topp->clk = 0;
    topp->eval();
    topp->wire0 = 7;
    topp->wire1 = 0;
    topp->clk = 1;
    topp->eval();
    std::cout << "O = " << std::bitset<8>(topp->O) << std::endl;

    // Final model cleanup
    topp->final();
    return 0;
}
```

### Actual Behavior

**Without** the `-fno-split` option, `O = 00000111`.

```sh
$ verilator -cc -exe -Wno-fatal -Wno-lint -Mdir default -build top.v main.cpp && ./default/Vtop          
make: Entering directory '/home/zyk/C/verilator/default'
... # Omitted
make: Leaving directory '/home/zyk/C/verilator/default'
O = 00000111
```

**With** the `-fno-split` option, `O = 00001111`.

```sh
$ verilator -cc -exe -Wno-fatal -Wno-lint -fno-split -Mdir no_split -build top.v main.cpp && ./no_split/Vtop
make: Entering directory '/home/zyk/C/verilator/no_split'
... # Omitted
make: Leaving directory '/home/zyk/C/verilator/no_split'
O = 00001111
```

### Verilator version

The latest git master (`729f8b9334ce01d289e31e59a126f1611b20736b`).

### OS version

WSL2 on Windows (Debian 10)
